import{_ as a,o as e,c as n,a as t}from"./chunks/framework.8tiMeCK-.js";const g=JSON.parse('{"title":"12.3  Network Topologies（网络拓扑）","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_networking/ch12_3.md","filePath":"notes/linux_kernel_networking/ch12_3.md","lastUpdated":null}'),i={name:"notes/linux_kernel_networking/ch12_3.md"};function r(o,s,p,l,d,h){return e(),n("div",null,[...s[0]||(s[0]=[t(`<h1 id="_12-3-network-topologies-网络拓扑" tabindex="-1">12.3 Network Topologies（网络拓扑） <a class="header-anchor" href="#_12-3-network-topologies-网络拓扑" aria-label="Permalink to &quot;12.3  Network Topologies（网络拓扑）&quot;">​</a></h1><p>搞定了帧头部的字节排列之后，我们需要退后一步，看看大局。</p><p>这些帧并不是在真空中飞来飞去的——它们是在某种特定的「社会关系」中被生产和消费的。这就是网络拓扑。802.11 定义了设备之间交互的「基本规则」，而在这些规则之上，最常见的就是我们要讲的第一种模式。</p><hr><h3 id="infrastructure-bss-基础架构模式" tabindex="-1">Infrastructure BSS（基础架构模式） <a class="header-anchor" href="#infrastructure-bss-基础架构模式" aria-label="Permalink to &quot;Infrastructure BSS（基础架构模式）&quot;">​</a></h3><p>这是绝大多数人日常接触的模式。你家里的路由器、公司的 Wi-Fi，本质上都是这一套东西。</p><p>在这个模式里，世界是不平等的：有一个中心节点，叫做 <strong>AP (Access Point，接入点)</strong>，周围围着一圈 <strong>Client Stations（客户端站点）</strong>。AP 和它的 clients 一起构成了一个 <strong>BSS (Basic Service Set，基本服务集)</strong>。</p><p>这就像是一个星型结构：所有的路都通向 AP。</p><p>但这并不是连上就能用的。客户端要想通过 AP 发数据，必须先完成两件事：<strong>认证</strong> 和 <strong>关联</strong>。</p><p>这听起来有点像官僚手续，但你得这么想：无线信道是共享的，AP 需要知道「你是谁」以及「你想干嘛」。在大多数情况下，客户端在敲 AP 的门之前，还会先做个 <strong>Scanning（扫描）</strong>，看看附近有哪些 AP，信号怎么样，支持什么速率。这就像你在进餐厅前先看看菜单和评分。</p><p>关联是排他的。在任何一个给定时刻，一个客户端只能跟一个 AP 绑定。你不能脚踩两只船。</p><p>一旦关联成功，AP 会发给客户端一个 <strong>AID (Association ID，关联 ID)</strong>。这是一个 1 到 2007 之间的数字，在当前 BSS 内唯一标识你这个客户端。</p><h4 id="ap-背后的机制" tabindex="-1">AP 背后的机制 <a class="header-anchor" href="#ap-背后的机制" aria-label="Permalink to &quot;AP 背后的机制&quot;">​</a></h4><p>站在内核开发者的角度看，AP 到底是个什么东西？</p><p>本质上，AP 就是一块加了些外围硬件（比如以太网口、LED 灯、那个让你绝望的 Reset 按钮）的无线网卡。但真正让它变成 AP 的，是跑在上面的软件。</p><p>这里有一个大名鼎鼎的角色：<strong>hostapd</strong>。</p><p>hostapd 是一个用户空间的守护进程。它处理 MLME（MAC 层管理实体）里那些繁重的管理任务，比如处理认证请求、关联请求。它怎么干活？通过 <strong>nl80211</strong> 接口注册自己，专门接收相关的管理帧。如果把这些管理帧比作行政文件，hostapd 就是那个坐在窗口后面盖章的人。</p><p>整个 hostapd 项目是开源的，它让无数普通的无线网卡具备了变身 AP 的能力。</p><h4 id="数据是如何流动的" tabindex="-1">数据是如何流动的？ <a class="header-anchor" href="#数据是如何流动的" aria-label="Permalink to &quot;数据是如何流动的？&quot;">​</a></h4><p>在 Infrastructure 模式下，通信几乎总是通过 AP 中转的。</p><ul><li><strong>Client → AP</strong>：客户端把数据包发给 AP。</li><li><strong>AP → Destination</strong>：AP 收到后，把它转发给最终的目标（可能是另一个无线客户端，也可能是通过有线网桥接出去的外网设备）。</li></ul><p>这种「所有人过河都要经过桥」的设计，虽然看起来低效，但极大地简化了管理。AP 掌握着全局的视野。</p><p>如果要覆盖很大的区域（比如一个大办公楼），一个 AP 搞不定。这时我们会部署多个 AP，然后用网线把它们连起来。这种部署架构叫做 <strong>ESS (Extended Service Set，扩展服务集)</strong>。在 ESS 里面，有两个或以上的 BSS 同时存在。</p><p>这里有个容易出错的细节：在 BSS A 里发出的广播包，飘到了隔壁的 BSS B 里，BSS B 里的站点会收到它，但必须<strong>丢弃</strong>它。为什么？因为 802.11 头部里的 <strong>BSSID</strong> 对不上。这就像你听到了隔壁教室的点名，虽然你听到了，但那不是在叫你。</p><p>所以在 ESS 部署里，为了避免互相打架，相邻的 AP 通常会工作在不同的信道上。</p><hr><h3 id="ibss-independent-bss-也就是-ad-hoc-模式" tabindex="-1">IBSS (Independent BSS)，也就是 Ad Hoc 模式 <a class="header-anchor" href="#ibss-independent-bss-也就是-ad-hoc-模式" aria-label="Permalink to &quot;IBSS (Independent BSS)，也就是 Ad Hoc 模式&quot;">​</a></h3><p>如果说 Infrastructure 模式是「中央集权」，那 IBSS 模式就是「无政府主义」。</p><p><strong>IBSS (Independent BSS)</strong> 通常被称为 <strong>Ad Hoc 网络</strong>。它不需要 AP，不需要路由器，大家凑在一起就能通信。这种网络通常是临时搭建的，用完即走，没有预规划。</p><h4 id="建立-ibss" tabindex="-1">建立 IBSS <a class="header-anchor" href="#建立-ibss" aria-label="Permalink to &quot;建立 IBSS&quot;">​</a></h4><p>建立 IBSS 的过程简单得令人发指。你不需要在内核里写复杂的逻辑，只需要在命令行敲两下。</p><p>用 <code>iw</code> 工具（这是新一代的工具）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlan0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ibss</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> join</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AdHocNetworkName</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2412</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 <code>2412</code> 指的是信道 1 的中心频率（单位 MHz）。</p><p>或者用老派的 <code>iwconfig</code>：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iwconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlan0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ad-hoc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iwconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wlan0</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> essid</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AdHocNetworkName</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>当你敲下回车的那一刻，内核会调用 <code>ieee80211_sta_create_ibss()</code> 方法（定义在 <code>net/mac80211/ibss.c</code>），IBSS 网络就诞生了。</p><p>当然，SSID（网络名）需要你想办法告诉所有想加入的人——手动输入，或者写在纸上拍张照发过去，随你便。</p><h4 id="ibss-的独特之处" tabindex="-1">IBSS 的独特之处 <a class="header-anchor" href="#ibss-的独特之处" aria-label="Permalink to &quot;IBSS 的独特之处&quot;">​</a></h4><p>既然没有 AP，那谁来管事？</p><p>没人管。</p><p>在 IBSS 模式下，<strong>BSSID</strong> 是一个随机生成的 48 位地址（通过调用 <code>get_random_bytes()</code> 实现）。因为没有中心节点，很多在 Infrastructure 模式下由 AP 代劳的事情，现在得大家商量着办，或者干脆不用了。</p><p>其中一个复杂得让人头疼的机制就是 <strong>Power Save（电源管理）</strong>。</p><p>在 Infrastructure 模式下，你睡觉，AP 帮你看门。但在 Ad Hoc 模式下，没有 AP 这位保姆。IBSS 使用了一种叫做 <strong>ATIM (Announcement Traffic Indication Map)</strong> 的消息来协调大家谁该醒着、谁该睡觉。</p><p>坦白说，ATIM 的机制相当复杂且脆弱，而且 <strong>mac80211 目前并不支持 ATIM</strong>。所以如果你在写驱动或者调试时指望这个功能，你会失望的。本章就不深入这个坑了。</p><hr><p>现在我们已经搞清楚了两种最基本的网络形态。在下一节，我们将深入那个 mac80211 栈里最重要的机制之一：<strong>Power Save Mode（节电模式）</strong>。我们来看看在 Infrastructure 模式下，AP 到底是怎么帮客户端「带信」的，以及这中间那些让无数驱动开发者掉过发的坑。</p>`,47)])])}const S=a(i,[["render",r]]);export{g as __pageData,S as default};
